import { Injectable, Inject, PLATFORM_ID } from '@angular/core';
import { isPlatformBrowser } from '@angular/common';
import {PDFDocument, PDFImage, PDFPage} from 'pdf-lib';
import { PDF_EXPORT_CONFIG, PdfExportConfig } from '../tokens/pdf-export-config.token';
import html2canvas from 'html2canvas';

interface PageDimensions {
  width: number;
  height: number;
}

interface PageSizeDefinition {
  name: string;
  width: number;  // in points
  height: number; // in points
}

interface ContentBreakPoint {
  y: number;
  priority: number; // Higher number = better break point
  elementType: string;
}

@Injectable()
export class PdfExportService {
  // Predefined page sizes in points (72 DPI)
  private readonly PAGE_SIZES: Record<string, PageSizeDefinition> = {
    'A4': { name: 'A4', width: 595.28, height: 841.89 },
    'A3': { name: 'A3', width: 841.89, height: 1190.55 },
    'A5': { name: 'A5', width: 419.53, height: 595.28 },
    'Letter': { name: 'Letter', width: 612, height: 792 },
    'Legal': { name: 'Legal', width: 612, height: 1008 },
    'Tabloid': { name: 'Tabloid', width: 792, height: 1224 },
    'Ledger': { name: 'Ledger', width: 1224, height: 792 },
    'Executive': { name: 'Executive', width: 522, height: 756 },
    'B4': { name: 'B4', width: 708.66, height: 1000.63 },
    'B5': { name: 'B5', width: 498.90, height: 708.66 }
  };

  constructor(
    @Inject(PDF_EXPORT_CONFIG) private readonly config: PdfExportConfig,
    @Inject(PLATFORM_ID) private readonly platformId: object
  ) {}

  async exportHtml(element: HTMLElement, overrideConfig?: PdfExportConfig): Promise<void> {
    if (!isPlatformBrowser(this.platformId)) {
      throw new Error('PDF export is only supported in browser environments.');
    }

    const config = { ...this.config, ...overrideConfig };

    // Get page dimensions based on configuration
    const pageSize = config.pageSize || 'A4';
    const orientation = config.orientation || 'portrait';
    const pageDimensions = this._getPageDimensions(pageSize, orientation);

    // Enhanced html2canvas options for high-quality PDF output
    const html2canvasOptions = {
      scale: 3, // Higher scale for crystal-clear resolution (3x)
      useCORS: true, // Enable CORS for external images
      allowTaint: false, // Prevent tainted canvas
      backgroundColor: '#ffffff', // Ensure white background
      logging: false, // Disable console logging
      imageTimeout: 15000, // Timeout for image loading
      removeContainer: true, // Clean up temporary containers
      foreignObjectRendering: true, // Better text rendering
      // High-quality rendering options
      imageSmoothingEnabled: true,
      imageSmoothingQuality: 'high' as any,
      letterRendering: true, // Better letter/font rendering
      // Preserve margins and padding by capturing full element bounds
      x: 0,
      y: 0,
      scrollX: 0,
      scrollY: 0,
      // Capture with original dimensions to preserve layout
      width: element.scrollWidth,
      height: element.scrollHeight,
      // Additional quality options
      dpi: 300, // High DPI for print quality
      windowWidth: window.innerWidth,
      windowHeight: window.innerHeight
    };

    // Convert HTML element to canvas with enhanced options
    const canvas: HTMLCanvasElement = await html2canvas(element, html2canvasOptions);

    // Calculate scale factor with margin consideration
    const scaleFactor = this._calculateScaleFactorWithMargins(canvas.width, pageDimensions.width, element);

    // Detect optimal break points in the content
    const breakPoints = this._detectContentBreakPoints(element, canvas, scaleFactor);

    // Calculate smart page breaks
    const pageBreaks = this._calculateSmartPageBreaks(canvas.height, scaleFactor, pageDimensions.height, breakPoints);

    // Create PDF document
    const pdf: PDFDocument = await PDFDocument.create();

    // Add metadata if provided
    if (config.metadata) {
      pdf.setTitle(config.metadata.title || '');
      pdf.setAuthor(config.metadata.author || '');
      pdf.setSubject(config.metadata.subject || '');
    }

    // Generate each page with smart breaks and improved quality
    for (let pageIndex = 0; pageIndex < pageBreaks.length; pageIndex++) {
      const currentBreak = pageBreaks[pageIndex];
      const nextBreak = pageBreaks[pageIndex + 1];

      // Create canvas for this page with smart bounds
      const pageCanvas = this._createSmartPageCanvas(
        canvas,
        currentBreak,
        nextBreak,
        scaleFactor,
        pageDimensions
      );

      // Convert page canvas to high-quality image data
      const pageImgData = pageCanvas.toDataURL('image/png', 1.0); // Maximum quality (1.0)

      // Add page to PDF with configured dimensions
      const page: PDFPage = pdf.addPage([pageDimensions.width, pageDimensions.height]);

      // Embed the image and draw it on the page
      const png: PDFImage = await pdf.embedPng(pageImgData);
      page.drawImage(png, {
        x: 0,
        y: 0,
        width: pageDimensions.width,
        height: pageDimensions.height
      });
    }

    // Save and download the PDF
    const bytes: Uint8Array = await pdf.save();
    this._triggerDownload(bytes, config.filename || 'document.pdf', config.openInNewTab);
  }

  private _triggerDownload(data: Uint8Array, filename: string, openInNewTab?: boolean): void {
    const blob = new Blob([data as BlobPart], { type: 'application/pdf' });
    const url: string = URL.createObjectURL(blob);

    if (openInNewTab) {
      window.open(url, '_blank');
    } else {
      const a: HTMLAnchorElement = document.createElement('a');
      a.href = url;
      a.download = filename;
      a.click();
    }

    URL.revokeObjectURL(url);
  }

  private _widthPxToPt(px: number): number {
    return (px * 72) / 96;
  }

  private _heightPxToPt(px: number): number {
    return (px * 72) / 96;
  }

  /**
   * Get page dimensions based on page size and orientation
   */
  private _getPageDimensions(pageSize: string = 'A4', orientation: 'portrait' | 'landscape' = 'portrait'): PageDimensions {
    const pageDef = this.PAGE_SIZES[pageSize.toUpperCase()];
    if (!pageDef) {
      throw new Error(`Unsupported page size: ${pageSize}. Supported sizes: ${Object.keys(this.PAGE_SIZES).join(', ')}`);
    }

    if (orientation === 'landscape') {
      return {
        width: pageDef.height,
        height: pageDef.width
      };
    } else {
      return {
        width: pageDef.width,
        height: pageDef.height
      };
    }
  }

  /**
   * Get available page sizes
   */
  public getAvailablePageSizes(): string[] {
    return Object.keys(this.PAGE_SIZES);
  }

  /**
   * Calculate the scale factor to fit content width to page width
   */
  private _calculateScaleFactor(canvasWidth: number, pageWidth: number): number {
    const contentWidthInPoints = this._widthPxToPt(canvasWidth);
    return pageWidth / contentWidthInPoints;
  }

  /**
   * Calculate scale factor with margin preservation
   */
  private _calculateScaleFactorWithMargins(canvasWidth: number, pageWidth: number, element: HTMLElement): number {
    // Get element's computed style to understand margins and padding
    const computedStyle = window.getComputedStyle(element);
    const marginLeft = parseFloat(computedStyle.marginLeft) || 0;
    const marginRight = parseFloat(computedStyle.marginRight) || 0;
    const paddingLeft = parseFloat(computedStyle.paddingLeft) || 0;
    const paddingRight = parseFloat(computedStyle.paddingRight) || 0;

    // Calculate effective content width (excluding margins/padding if needed)
    const totalHorizontalSpacing = marginLeft + marginRight + paddingLeft + paddingRight;

    // Get the actual content width from the element
    const elementWidth = element.offsetWidth;
    const elementScrollWidth = element.scrollWidth;

    // Use the larger width to ensure full content capture
    const effectiveWidth = Math.max(elementWidth, elementScrollWidth, canvasWidth);

    // Convert to points and calculate scale factor
    const contentWidthInPoints = this._widthPxToPt(effectiveWidth);

    // Leave some margin in PDF (10% on each side for better appearance)
    const pdfMargin = pageWidth * 0.1; // 5% margin on each side
    const availablePageWidth = pageWidth - pdfMargin;

    const scaleFactor = availablePageWidth / contentWidthInPoints;

    // Ensure scale factor doesn't exceed 1 for high-resolution displays
    return Math.min(scaleFactor, 1);
  }

  /**
   * Calculate how many pages are needed for the given content height
   */
  private _calculateRequiredPages(canvasHeight: number, scaleFactor: number, pageHeight: number): number {
    const scaledHeightInPoints = this._heightPxToPt(canvasHeight) * scaleFactor;
    return Math.ceil(scaledHeightInPoints / pageHeight);
  }

  /**
   * Detect optimal content break points by analyzing element boundaries
   */
  private _detectContentBreakPoints(element: HTMLElement, canvas: HTMLCanvasElement, scaleFactor: number): ContentBreakPoint[] {
    const breakPoints: ContentBreakPoint[] = [];

    // Add start point
    breakPoints.push({ y: 0, priority: 10, elementType: 'start' });

    // Find elements with page-break CSS properties
    const sectionsElements = element.querySelectorAll('.pdf-section, section, .content-block, .blog-card, .feature-card');

    sectionsElements.forEach((el) => {
      const htmlEl = el as HTMLElement;
      const rect = htmlEl.getBoundingClientRect();
      const elementRect = element.getBoundingClientRect();

      // Calculate relative position to the exported element
      const relativeTop = rect.top - elementRect.top;
      const relativeBottom = rect.bottom - elementRect.top;

      // Convert to canvas coordinates
      const canvasTop = relativeTop * (canvas.height / element.scrollHeight);
      const canvasBottom = relativeBottom * (canvas.height / element.scrollHeight);

      // Check CSS page-break properties
      const computedStyle = window.getComputedStyle(htmlEl);
      const pageBreakBefore = computedStyle.getPropertyValue('page-break-before');
      const pageBreakAfter = computedStyle.getPropertyValue('page-break-after');
      const pageBreakInside = computedStyle.getPropertyValue('page-break-inside');

      // Add break point before element if requested
      if (pageBreakBefore === 'always' || pageBreakBefore === 'auto') {
        breakPoints.push({
          y: canvasTop,
          priority: pageBreakBefore === 'always' ? 9 : 7,
          elementType: htmlEl.className || htmlEl.tagName.toLowerCase()
        });
      }

      // Add break point after element if requested
      if (pageBreakAfter === 'always' || pageBreakAfter === 'auto') {
        breakPoints.push({
          y: canvasBottom,
          priority: pageBreakAfter === 'always' ? 9 : 7,
          elementType: htmlEl.className || htmlEl.tagName.toLowerCase()
        });
      }

      // If element should not be broken inside, add high-priority boundaries
      if (pageBreakInside === 'avoid') {
        breakPoints.push({
          y: canvasTop,
          priority: 8,
          elementType: `${htmlEl.className || htmlEl.tagName.toLowerCase()}-start`
        });
        breakPoints.push({
          y: canvasBottom,
          priority: 8,
          elementType: `${htmlEl.className || htmlEl.tagName.toLowerCase()}-end`
        });
      }
    });

    // Add end point
    breakPoints.push({ y: canvas.height, priority: 10, elementType: 'end' });

    // Sort by Y position
    breakPoints.sort((a, b) => a.y - b.y);

    // Remove duplicates and very close points
    const cleanedBreakPoints: ContentBreakPoint[] = [];
    for (let i = 0; i < breakPoints.length; i++) {
      const current = breakPoints[i];
      const lastAdded = cleanedBreakPoints[cleanedBreakPoints.length - 1];

      // Keep if it's the first point or far enough from the last point
      if (!lastAdded || Math.abs(current.y - lastAdded.y) > 20) {
        cleanedBreakPoints.push(current);
      } else if (current.priority > lastAdded.priority) {
        // Replace with higher priority point
        cleanedBreakPoints[cleanedBreakPoints.length - 1] = current;
      }
    }

    return cleanedBreakPoints;
  }

  /**
   * Calculate smart page breaks that respect content boundaries
   */
  private _calculateSmartPageBreaks(canvasHeight: number, scaleFactor: number, pageHeight: number, breakPoints: ContentBreakPoint[]): number[] {
    const pageHeightPx = (pageHeight * 96) / 72 / scaleFactor;
    const pageBreaks: number[] = [];

    let currentPageStart = 0;
    pageBreaks.push(currentPageStart);

    while (currentPageStart < canvasHeight) {
      const idealPageEnd = currentPageStart + pageHeightPx;

      if (idealPageEnd >= canvasHeight) {
        // Last page
        break;
      }

      // Find the best break point near the ideal page end
      let bestBreakPoint = idealPageEnd;
      let bestPriority = 0;

      // Look for break points within a reasonable range of the ideal end
      const searchRange = pageHeightPx * 0.2; // 20% of page height
      const searchStart = Math.max(currentPageStart + pageHeightPx * 0.5, idealPageEnd - searchRange);
      const searchEnd = idealPageEnd + searchRange;

      for (const breakPoint of breakPoints) {
        if (breakPoint.y >= searchStart && breakPoint.y <= searchEnd && breakPoint.y > currentPageStart) {
          if (breakPoint.priority > bestPriority) {
            bestBreakPoint = breakPoint.y;
            bestPriority = breakPoint.priority;
          }
        }
      }

      // If no good break point found, use the ideal position
      if (bestPriority === 0) {
        bestBreakPoint = idealPageEnd;
      }

      currentPageStart = bestBreakPoint;
      pageBreaks.push(currentPageStart);
    }

    return pageBreaks;
  }

  /**
   * Create a canvas section for a specific page with smart boundaries
   */
  private _createSmartPageCanvas(
    sourceCanvas: HTMLCanvasElement,
    pageStartY: number,
    pageEndY: number | undefined,
    scaleFactor: number,
    pageDimensions: PageDimensions
  ): HTMLCanvasElement {
    const pageCanvas = document.createElement('canvas');
    const ctx = pageCanvas.getContext('2d')!;

    // Ultra high resolution canvas for crystal-clear quality (4x)
    const resolution = 4;
    const pageWidthPx = (pageDimensions.width * 96) / 72;
    const pageHeightPx = (pageDimensions.height * 96) / 72;

    // Set canvas size with ultra high resolution
    pageCanvas.width = pageWidthPx * resolution;
    pageCanvas.height = pageHeightPx * resolution;

    // Scale the canvas back down using CSS
    pageCanvas.style.width = pageWidthPx + 'px';
    pageCanvas.style.height = pageHeightPx + 'px';

    // Scale the context to match the ultra high resolution
    ctx.scale(resolution, resolution);

    // Enable maximum quality image rendering
    ctx.imageSmoothingEnabled = true;
    ctx.imageSmoothingQuality = 'high';

    // Additional quality settings for crisp rendering
    ctx.textBaseline = 'top';
    ctx.fillStyle = 'white';
    ctx.fillRect(0, 0, pageWidthPx, pageHeightPx);

    // Calculate margins for better appearance (5% on each side)
    const marginX = pageWidthPx * 0.05;
    const marginY = pageHeightPx * 0.05;
    const availableWidth = pageWidthPx - (marginX * 2);
    const availableHeight = pageHeightPx - (marginY * 2);

    // Calculate source height for this page
    const sourceHeight = pageEndY ? (pageEndY - pageStartY) : (sourceCanvas.height - pageStartY);

    if (sourceHeight > 0) {
      // Calculate scaled dimensions while preserving aspect ratio
      const sourceAspectRatio = sourceCanvas.width / sourceHeight;
      let destWidth = availableWidth;
      let destHeight = destWidth / sourceAspectRatio;

      // If height exceeds available space, scale by height instead
      if (destHeight > availableHeight) {
        destHeight = availableHeight;
        destWidth = destHeight * sourceAspectRatio;
      }

      // Center the content horizontally if it's smaller than available width
      const offsetX = marginX + (availableWidth - destWidth) / 2;
      const offsetY = marginY;

      // Draw the source canvas section onto the page canvas with margins and high quality
      ctx.drawImage(
        sourceCanvas,
        0, pageStartY, sourceCanvas.width, sourceHeight, // source (x, y, width, height)
        offsetX, offsetY, destWidth, destHeight // destination (x, y, width, height)
      );
    }

    return pageCanvas;
  }

  /**
   * Create a canvas section for a specific page
   */
  private _createPageCanvas(sourceCanvas: HTMLCanvasElement, pageIndex: number, scaleFactor: number, pageDimensions: PageDimensions): HTMLCanvasElement {
    const pageCanvas = document.createElement('canvas');
    const ctx = pageCanvas.getContext('2d')!;

    // Higher resolution for better quality
    const resolution = 2;
    const pageWidthPx = (pageDimensions.width * 96) / 72;
    const pageHeightPx = (pageDimensions.height * 96) / 72;

    // Set canvas size with high resolution
    pageCanvas.width = pageWidthPx * resolution;
    pageCanvas.height = pageHeightPx * resolution;

    // Scale the canvas back down using CSS
    pageCanvas.style.width = pageWidthPx + 'px';
    pageCanvas.style.height = pageHeightPx + 'px';

    // Scale the context to match the device pixel ratio
    ctx.scale(resolution, resolution);

    // Enable high-quality image rendering
    ctx.imageSmoothingEnabled = true;
    ctx.imageSmoothingQuality = 'high';

    // Fill with white background
    ctx.fillStyle = 'white';
    ctx.fillRect(0, 0, pageWidthPx, pageHeightPx);

    // Add margins for better appearance
    const marginX = pageWidthPx * 0.05;
    const marginY = pageHeightPx * 0.05;
    const availableWidth = pageWidthPx - (marginX * 2);
    const availableHeight = pageHeightPx - (marginY * 2);

    // Calculate the height of content that fits on one page in source canvas pixels
    const contentHeightPerPage = availableHeight / scaleFactor;

    // Calculate source coordinates for this page
    const sourceY = pageIndex * contentHeightPerPage;
    const sourceHeight = Math.min(contentHeightPerPage, sourceCanvas.height - sourceY);

    if (sourceHeight > 0) {
      // Calculate scaled dimensions while preserving aspect ratio
      const sourceAspectRatio = sourceCanvas.width / sourceHeight;
      let destWidth = availableWidth;
      let destHeight = destWidth / sourceAspectRatio;

      // If height exceeds available space, scale by height instead
      if (destHeight > availableHeight) {
        destHeight = availableHeight;
        destWidth = destHeight * sourceAspectRatio;
      }

      // Center the content
      const offsetX = marginX + (availableWidth - destWidth) / 2;
      const offsetY = marginY;

      // Draw the source canvas section onto the page canvas with margins and high quality
      ctx.drawImage(
        sourceCanvas,
        0, sourceY, sourceCanvas.width, sourceHeight, // source (x, y, width, height)
        offsetX, offsetY, destWidth, destHeight // destination (x, y, width, height)
      );
    }

    return pageCanvas;
  }
}
