// pdf-export.component.ts
import { Component, ContentChild, ElementRef, Input, ChangeDetectionStrategy } from '@angular/core';
import { PdfExportService } from '../services/pdf-export.service';
import { PdfExportConfig, PageSize, PageOrientation } from '../tokens/pdf-export-config.token';

@Component({
  selector: 'rm-pdf-export',
  changeDetection: ChangeDetectionStrategy.Eager,
  template: `<ng-content></ng-content><button (click)="export()">Export PDF</button>`
})
export class PdfExportComponent {
  @ContentChild('pdfContent', { read: ElementRef, static: true }) content!: ElementRef;

  // Individual configuration inputs
  @Input() pageSize?: PageSize;
  @Input() orientation?: PageOrientation;
  @Input() filename?: string;
  @Input() openInNewTab?: boolean;

  // Full configuration object input (takes precedence)
  @Input() pdfConfig?: PdfExportConfig;

  constructor(private readonly svc: PdfExportService) {}

  async export(): Promise<void> {
    // Build configuration from individual inputs or use provided config
    const config: PdfExportConfig = this.pdfConfig || {
      pageSize: this.pageSize,
      orientation: this.orientation,
      filename: this.filename,
      openInNewTab: this.openInNewTab
    };

    await this.svc.exportHtml(this.content.nativeElement, config);
  }
}
