// pdf-export-config.token.ts
import { InjectionToken } from '@angular/core';

export type PageSize = 'A4' | 'A3' | 'A5' | 'Letter' | 'Legal' | 'Tabloid' | 'Ledger' | 'Executive' | 'B4' | 'B5';
export type PageOrientation = 'portrait' | 'landscape';

export interface PdfExportConfig {
  pageSize?: PageSize; // e.g. 'A4'
  orientation?: PageOrientation;
  margins?: { top: number; bottom: number; left: number; right: number };
  filename?: string;
  metadata?: { title?: string; author?: string; subject?: string };
  openInNewTab?: boolean;
}

export const PDF_EXPORT_CONFIG = new InjectionToken<PdfExportConfig>('PDF_EXPORT_CONFIG');
